var e=[{id:`L2_1`,type:`dialog`,speaker:`DINO_RAS_NULL_NULL`,text:{KOREA:`사장은 눈이 예뻐요. 아늑하고 편안한 기분도 들어요. 우리가 돌아갈 집이 있다면, 그게 사장이었으면 좋겠어요.`,JPN:`社長は目が綺麗ね。心地よくてリラックスした気分にもなる。シェパードたちに帰る家があったら、それが社長だったらいいなあ。`,ENG:`You have pretty eyes, Boss. Looking into them make Shepherd feel cozy and at ease. If we have a home to go back to, Shepherd hopes that it's you, Boss.`,TWN:`老闆的眼睛很漂亮。讓人感覺溫暖又安心。如果有一個家可以收留我們，牧羊犬希望會是老闆。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DINO_RAS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`DINO_RAS_NULL_NULL`,text:{KOREA:`러처도 그렇게 생각하지?`,JPN:`ラッチャーもそう思うよね？`,ENG:`Don't you think so too, Lurcher?`,TWN:`獵犬，你也這麼認為吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DINO_RAS_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};